import type { NotificationPriority } from '../events/event-types.js';

const DEFAULT_ROUTING: Record<NotificationPriority, string> = {
  urgent: 'sms',
  normal: 'email',
  low: 'webhook',
};

export class PriorityRouter {
  private routing: Record<NotificationPriority, string>;

  constructor(routing?: Partial<Record<NotificationPriority, string>>) {
    this.routing = { ...DEFAULT_ROUTING, ...routing };
  }

  /**
   * Resolve which channel a notification should be routed to based on its priority.
   */
  route(priority: NotificationPriority): string {
    return this.routing[priority];
  }

  /**
   * Get the full routing table.
   */
  getRoutingTable(): Record<NotificationPriority, string> {
    return { ...this.routing };
  }
}

