/**
 * Send a notification — stores locally and publishes to EventBus for channel handlers.
 *
 * Channel is determined by priority-based routing:
 *   - urgent → sms
 *   - normal → email
 *   - low    → webhook
 *
 * An explicit `channel` override is still supported for backward compatibility,
 * but the preferred approach is to set `priority` and let the router decide.
 */
sendNotification(params: {
  recipient: string;
  subject: string;
  body: string;
  priority?: NotificationPriority;
  channel?: string;
}): void {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);

  // Priority-based routing: use priority to determine channel, fall back to
  // explicit channel override, then default to 'normal' priority (email).
  const priority = params.priority ?? 'normal';
  const channel = params.channel ?? this.priorityRouter.route(priority);
  this.eventBus.emit<NotificationRequestedEvent>({
    type: 'notification:requested',
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    channel,
    priority,
    timestamp: new Date(),
  });
}

