import { describe, it, expect, beforeEach } from 'vitest';
import { PriorityRouter } from '../../src/services/priority-router.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailChannelHandler,
  SmsChannelHandler,
  WebhookChannelHandler,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';

describe('PriorityRouter', () => {
  it('should route urgent to sms', () => {
    const router = new PriorityRouter();
    expect(router.route('urgent')).toBe('sms');
  });

  it('should route normal to email', () => {
    const router = new PriorityRouter();
    expect(router.route('normal')).toBe('email');
  });

  it('should route low to webhook', () => {
    const router = new PriorityRouter();
    expect(router.route('low')).toBe('webhook');
  });

  it('should allow custom routing overrides', () => {
    const router = new PriorityRouter({ urgent: 'email' });
    expect(router.route('urgent')).toBe('email');
    expect(router.route('normal')).toBe('email');
    expect(router.route('low')).toBe('webhook');
  });

  it('should expose the routing table', () => {
    const router = new PriorityRouter();
    expect(router.getRoutingTable()).toEqual({
      urgent: 'sms',
      normal: 'email',
      low: 'webhook',
    });
  });
});

describe('Priority-based routing integration', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let emailHandler: EmailChannelHandler;
  let smsHandler: SmsChannelHandler;
  let webhookHandler: WebhookChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();

    emailHandler = new EmailChannelHandler(eventBus);
    smsHandler = new SmsChannelHandler(eventBus);
    webhookHandler = new WebhookChannelHandler(eventBus, 'https://hooks.example.com/notify');

    service = new NotificationService(eventBus);
  });

  it('should route urgent notifications to SMS', async () => {
    service.sendNotification({
      recipient: '+1234567890',
      subject: 'Server Down',
      body: 'Production server is unresponsive',
      priority: 'urgent',
    });

    expect(smsHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(emailHandler.getDeliveredNotifications()).toHaveLength(0);
    expect(webhookHandler.getDeliveredNotifications()).toHaveLength(0);
  });

  it('should route normal notifications to email', async () => {
    service.sendNotification({
      recipient: 'alice@example.com',
      subject: 'Weekly Report',
      body: 'Your weekly report is ready',
      priority: 'normal',
    });

    expect(emailHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(smsHandler.getDeliveredNotifications()).toHaveLength(0);
    expect(webhookHandler.getDeliveredNotifications()).toHaveLength(0);
  });

  it('should route low-priority notifications to webhook', async () => {
    service.sendNotification({
      recipient: 'system-log',
      subject: 'Metric Update',
      body: 'Daily metrics have been collected',
      priority: 'low',
    });

    expect(webhookHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(emailHandler.getDeliveredNotifications()).toHaveLength(0);
    expect(smsHandler.getDeliveredNotifications()).toHaveLength(0);
  });

  it('should default to normal priority (email) when no priority specified', async () => {
    service.sendNotification({
      recipient: 'alice@example.com',
      subject: 'Hello',
      body: 'Default priority test',
    });

    expect(emailHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(smsHandler.getDeliveredNotifications()).toHaveLength(0);
    expect(webhookHandler.getDeliveredNotifications()).toHaveLength(0);
  });

  it('should allow explicit channel override to bypass priority routing', async () => {
    service.sendNotification({
      recipient: 'alice@example.com',
      subject: 'Override Test',
      body: 'Explicit channel should win',
      priority: 'urgent',
      channel: 'email',
    });

    // Explicit channel='email' overrides the urgent→sms routing
    expect(emailHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(smsHandler.getDeliveredNotifications()).toHaveLength(0);
  });

  it('should include priority in the emitted event', async () => {
    service.sendNotification({
      recipient: 'alice@example.com',
      subject: 'Priority Event',
      body: 'Check the event',
      priority: 'urgent',
    });

    const eventLog = eventBus.getEventLog();
    const notifEvent = eventLog.find((e) => e.type === 'notification:requested');
    expect(notifEvent).toBeDefined();
    if (notifEvent?.type === 'notification:requested') {
      expect(notifEvent.priority).toBe('urgent');
      expect(notifEvent.channel).toBe('sms');
    }
  });

  it('should route multiple notifications with different priorities correctly', async () => {
    service.sendNotification({
      recipient: '+1234567890',
      subject: 'Urgent',
      body: 'Urgent message',
      priority: 'urgent',
    });
    service.sendNotification({
      recipient: 'alice@example.com',
      subject: 'Normal',
      body: 'Normal message',
      priority: 'normal',
    });
    service.sendNotification({
      recipient: 'system-log',
      subject: 'Low',
      body: 'Low priority message',
      priority: 'low',
    });

    expect(smsHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(emailHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(webhookHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(service.getNotificationCount()).toBe(3);
  });

  it('should work with a custom priority router', async () => {
    const customRouter = new PriorityRouter({ urgent: 'email', normal: 'webhook' });
    const customService = new NotificationService(eventBus, customRouter);

    customService.sendNotification({
      recipient: 'alice@example.com',
      subject: 'Custom Routing',
      body: 'Urgent routed to email',
      priority: 'urgent',
    });

    expect(emailHandler.getDeliveredNotifications()).toHaveLength(1);
    expect(smsHandler.getDeliveredNotifications()).toHaveLength(0);
  });
});

